        var items = CreateItems(("Widget", 10.00m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

