         // Assert
         var after = DateTime.UtcNow;
         Assert.IsTrue(order.CreatedAt >= before, "CreatedAt should be at or after test start");
         Assert.IsTrue(order.CreatedAt <= after, "CreatedAt should be at or before test end");
     }

